import React from 'react';

interface ProductCardProps {
 id: number;
 name: string;
 weight: string;
 price: number;
 oldPrice?: number;
 discount?: string;
 imageColor: string;
 onAdd: () => void;
}

const ProductCard: React.FC<ProductCardProps> = ({ name, weight, price, oldPrice, discount, imageColor, onAdd }) => {
 return (
  <div className="group cursor-pointer flex flex-col h-full">
   <div className="relative aspect-square rounded-[24px] overflow-hidden mb-4 bg-[#F7F7F7] transition-all group-hover:shadow-md">
    {/* Placeholder for product image */}
    <div className="absolute inset-0 flex items-center justify-center p-6">
     <div className={`w-full h-full rounded-2xl ${imageColor} opacity-80 group-hover:scale-105 transition-transform duration-500 shadow-sm`} />
    </div>

    {discount && (
     <div className="absolute top-3 left-3 bg-[#111] text-white text-[11px] font-bold px-2 py-0.5 rounded-md">
      {discount}
     </div>
    )}
   </div>

   <div className="flex-1 flex flex-col px-1">
    <h3 className="text-[12px] font-medium text-black leading-tight line-clamp-2 mb-1">
     {name}
    </h3>
    <p className="text-[11px] text-[#999] mb-3">
     {weight} • <span className="text-[#FF4242] font-semibold cursor-pointer hover:underline">Снизили цену</span>
    </p>

    <div className="mt-auto flex items-center justify-between">
     <div className="flex items-baseline gap-1.5">
      <span className="text-[14px] font-[800] text-[#FF4242]">{price} ₽</span>
      {oldPrice && (
       <span className="text-[11px] text-[#999] line-through">{oldPrice} </span>
      )}
     </div>

     <button
      onClick={(e) => {
       e.stopPropagation();
       onAdd();
      }}
      className="flex h-7 w-7 items-center justify-center rounded-full bg-[#FFF0F0] text-[#FF4242] hover:bg-[#FF4242] hover:text-white transition-all transform active:scale-90"
     >
      <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
       <path d="M12 5v14M5 12h14" />
      </svg>
     </button>
    </div>
   </div>
  </div>
 );
};

export default ProductCard;
