import React from 'react';

const PromoBanners = () => {
 return (
  <div className="grid grid-cols-1 md:grid-cols-3 gap-6 px-8 md:px-14 py-8 max-w-[1440px] mx-auto">
   {/* Banner 1: Morning Special */}
   <div className="relative h-[250px] rounded-[32px] overflow-hidden bg-[#FAF3E8] p-10 flex flex-col justify-between group cursor-pointer transition-transform hover:scale-[1.01]">
    <div className="z-10">
     <span className="inline-block px-3 py-1 bg-[#E8C4A0]/20 rounded-full text-[11px] font-bold text-[#AE713F] uppercase tracking-wider mb-5">
      Morning Special
     </span>
     <h2 className="text-[34px] font-extrabold leading-[1.05] text-black max-w-[220px]">
      Buy 1 Cinnamon Roll, get coffee free
     </h2>
    </div>
    <button className="z-10 w-fit px-6 py-2.5 bg-white rounded-full text-[12px] font-extrabold text-black transition-all hover:bg-black hover:text-white card-shadow">
     Claim offer →
    </button>
    {/* Abstract Croissant / Swirl Shape */}
    <div className="absolute right-[-40px] top-[20px] w-[220px] h-[220px] opacity-90 group-hover:rotate-6 transition-transform duration-700">
     <div className="w-full h-full bg-[#E8C4A0] rounded-[60%_40%_70%_30%_/_50%_40%_60%_50%] rotate-45 blur-[2px]" />
     <div className="absolute inset-4 bg-[#D1A67B] rounded-full blur-[40px] opacity-40" />
    </div>
   </div>

   {/* Banner 2: New Arrival */}
   <div className="relative h-[250px] rounded-[32px] overflow-hidden bg-[#E8EFF7] p-10 flex flex-col justify-between group cursor-pointer transition-transform hover:scale-[1.01]">
    <div className="z-10">
     <span className="inline-block px-3 py-1 bg-[#A0C4E8]/20 rounded-full text-[11px] font-bold text-[#4F86AE] uppercase tracking-wider mb-5">
      New Arrival
     </span>
     <h2 className="text-[34px] font-extrabold leading-[1.05] text-black">
      Parisian Box
     </h2>
     <p className="text-[13px] text-[#666] mt-3 font-medium">Assortment of 6 freshly baked croissants.</p>
    </div>
    <button className="z-10 w-fit px-6 py-2.5 bg-white rounded-full text-[12px] font-extrabold text-black transition-all hover:bg-black hover:text-white card-shadow">
     Order now
    </button>
    {/* Box Shape visual */}
    <div className="absolute right-[-20px] bottom-[-20px] w-[180px] h-[180px] bg-white opacity-40 rotate-[15deg] blur-sm group-hover:rotate-[20deg] transition-transform" />
   </div>

   {/* Banner 3: Generic Container */}
   <div className="relative h-[250px] rounded-[32px] overflow-hidden bg-gradient-to-b from-[#D0D0D0] to-[#999999] p-10 flex flex-col justify-end group cursor-pointer transition-transform hover:scale-[1.01]">
    <div className="absolute inset-0 bg-black/5" />
    <div className="z-10 text-white">
     <h2 className="text-[34px] font-extrabold text-white leading-tight">Container</h2>
     <p className="text-[13px] text-white/70 mt-1 font-medium italic">Aged 48 hours. Baked this morning.</p>
    </div>
    {/* Abstract metallic / grey shapes */}
    <div className="absolute top-[-40px] left-[-40px] w-[150px] h-[150px] bg-white/10 rounded-full blur-2xl" />
    <div className="absolute right-10 bottom-20 w-[100px] h-[100px] border border-white/20 rounded-full" />
   </div>
  </div>
 );
};

export default PromoBanners;
